import { useState, useEffect } from 'react';
import './PromoBanner.css';

function PromoBanner() {
  const promotions = [
    { text: '🔥 20% OFF ALL GROCERIES THIS WEEKEND!', image: '/images/promo1.jpg' },
    { text: '🎉 BUY 2 GET 1 FREE ON SELECT BEVERAGES!', image: '/images/promo1.jpg' },
    { text: '🚀 FREE DELIVERY FOR ORDERS ABOVE ₦5000!', image: '/images/promo1.jpg' },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((currentIndex + 1) % promotions.length);
    }, 4000); // 4 seconds

    return () => clearInterval(interval);
  }, [currentIndex, promotions.length]);

  const currentPromotion = promotions[currentIndex];

  return (
    <div
      className="promo-banner"
      style={{ backgroundImage: `url(${currentPromotion.image})` }}
    >
      <div className="promo-text">
        {currentPromotion.text}
      </div>
    </div>
  );
}

export default PromoBanner;
